fixed_code:
method FindLongWords(s: string) returns (words: seq<string>)
  ensures forall w :: w in words ==> |w| >= 4
  ensures forall w :: w in words ==> exists i, j :: 0 <= i <= j < |s| && s[i..j+1] == w
{
  var result := [];
  var start := 0;
  var i := 0;

  while i <= |s|
    invariant 0 <= start <= i
    invariant forall w :: w in result ==> |w| >= 4
    invariant forall w :: w in result ==> exists a, b :: 0 <= a <= b < |s| && s[a..b+1] == w
    decreases |s| - i
  {
    if i == |s| || s[i] == ' ' {
      var word := s[start..i];
      if |word| >= 4 {
          SubstringIsSubpart(s, start, i - 1);
        result := result + [word];
      }
      start := i + 1;
    }
    i := i + 1;
  }

  words := result;
}

lemma SubstringIsSubpart(s: string, i: int, j: int)
  requires 0 <= i <= j < |s|
  ensures exists a, b :: 0 <= a <= b < |s| && s[a..b+1] == s[i..j+1]
{
  // 通过显式给出 witness（a = i, b = j）来证明存在性
  var a := i;
  var b := j;
  assert 0 <= a <= b < |s|;
  assert s[a..b+1] == s[i..j+1];
}
